{
  "terms": [
    {
      "term": "Generation",
      "simpleDefinition": "The process of converting energy (like wind, gas, or nuclear) into electrical power.",
      "anchor": "The 'start point' of the electrical journey.",
      "misconception": "Thinking electricity is created from nothing; it is always converted from another energy source."
    },
    {
      "term": "Transmission",
      "simpleDefinition": "The bulk movement of electricity over long distances using very high voltages.",
      "anchor": "The 'motorway' of the electrical system.",
      "misconception": "Confusing transmission with distribution; transmission is the high-voltage long-distance stage."
    },
    {
      "term": "Transmission Voltages",
      "simpleDefinition": "The three specific high voltages used in the UK grid: 400 kV, 275 kV, and 132 kV.",
      "anchor": "The 'Big Three' high-pressure levels.",
      "misconception": "Believing 11 kV or 33 kV are transmission voltages; those are actually for local distribution."
    },
    {
      "term": "Micro-generation",
      "simpleDefinition": "Small-scale production of electricity, usually by individual homeowners or small businesses.",
      "anchor": "Local power, like solar panels on a house roof.",
      "misconception": "Thinking micro-generation only works off-grid; most systems feed back into the National Grid."
    },
    {
      "term": "I²R Losses",
      "simpleDefinition": "Power lost as heat when current flows through the resistance of a cable.",
      "anchor": "Wasted heat in the wires.",
      "misconception": "Thinking high voltage is used to make electricity 'faster'; it is actually used to lower the current and reduce heat loss."
    }
  ],
  "anchorPhrases": [
    "400 kV, 275 kV, and 132 kV",
    "High voltage, low current",
    "Reducing I²R losses",
    "Centralised generation vs micro-generation"
  ],
  "misconceptionTargets": [
    "11kV is a transmission voltage",
    "High voltage is used to make electricity travel faster",
    "Micro-generation is only for large wind farms"
  ]
}

{
  "teachChecks": [
    {
      "title": "The National Grid Concept",
      "basicQuestions": [
        {
          "questionText": "What does the National Grid connect power stations to?",
          "answerGuidance": [
            "Consumers",
            "Load centers",
            "Places where electricity is used"
          ],
          "hint": "Think about the end-user of the electricity.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "Why must electricity be generated at the exact moment it is needed?",
          "answerGuidance": [
            "It is not stored in large quantities",
            "Electricity is not stored on the grid",
            "Demand must match generation in real-time"
          ],
          "hint": "Consider whether the grid acts as a battery or a delivery system.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        },
        {
          "questionText": "What is the primary function of the National Grid in terms of power movement?",
          "answerGuidance": [
            "Bulk power delivery",
            "Moving power across the country",
            "High-capacity delivery network"
          ],
          "hint": "Think of the motorway analogy used in the text.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        }
      ],
      "deeperQuestionText": "How does the National Grid maintain a continuous supply of power if a single power station experiences a technical failure?",
      "deeperAnswerGuidance": [
        "Other power stations pick up the load",
        "The network is interconnected",
        "Redundancy prevents blackouts",
        "Generation is adjusted across the grid to match demand"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP4"
      ],
      "hint": "Consider how an interconnected network handles the loss of one of its sources."
    },
    {
      "title": "Standard Transmission Voltages",
      "basicQuestions": [
        {
          "questionText": "What is the highest standard transmission voltage used on the UK mainland grid?",
          "answerGuidance": [
            "400 kV",
            "400,000 volts"
          ],
          "hint": "It is the largest of the three numbers mentioned.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "What does the abbreviation 'kV' stand for?",
          "answerGuidance": [
            "Kilovolt",
            "Kilovolts",
            "1,000 volts"
          ],
          "hint": "The 'k' represents a thousand.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        },
        {
          "questionText": "Besides 400 kV and 132 kV, what is the third standard UK transmission voltage?",
          "answerGuidance": [
            "275 kV"
          ],
          "hint": "It is the middle value in the transmission range.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        }
      ],
      "deeperQuestionText": "Why are 11 kV and 33 kV not classified as transmission voltages in the UK power system?",
      "deeperAnswerGuidance": [
        "They are used for local distribution",
        "They are not for long-distance bulk movement",
        "Transmission requires higher voltages for efficiency",
        "They represent a different stage of the supply chain"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP4"
      ],
      "hint": "Think about the specific purpose of transmission versus distribution."
    },
    {
      "title": "Large-Scale Generation Methods",
      "basicQuestions": [
        {
          "questionText": "Which generation method involves burning organic materials like wood pellets?",
          "answerGuidance": [
            "Biomass"
          ],
          "hint": "This term refers to fuel derived from living or recently living organisms.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        },
        {
          "questionText": "What do fossil fuel power stations typically produce to turn their turbines?",
          "answerGuidance": [
            "Steam"
          ],
          "hint": "Burning the fuel heats water to create this gas.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "Name one large-scale renewable generation method that uses the movement of water.",
          "answerGuidance": [
            "Hydroelectric",
            "Hydro",
            "Wave"
          ],
          "hint": "Think of natural water forces used at a grid-scale level.",
          "sourceTeachingPointIds": [
            "TP4"
          ]
        }
      ],
      "deeperQuestionText": "What is the fundamental difference between centralized large-scale generation and the way power is delivered to the end user?",
      "deeperAnswerGuidance": [
        "Power is made in one large plant and sent far away",
        "It requires a transmission grid to reach consumers",
        "It is produced in bulk rather than locally",
        "It feeds directly into the high-voltage transmission network"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP2"
      ],
      "hint": "Focus on the location of production versus the location of use."
    },
    {
      "title": "Micro-Generation and Local Supply",
      "basicQuestions": [
        {
          "questionText": "What specific technology uses solar panels to convert sunlight into electricity?",
          "answerGuidance": [
            "Photovoltaic",
            "PV"
          ],
          "hint": "The term starts with 'P' and relates to light and voltage.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "What term describes power production that happens at the point of use rather than at a central station?",
          "answerGuidance": [
            "Decentralized",
            "Local generation"
          ],
          "hint": "It is the opposite of 'centralized'.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        },
        {
          "questionText": "What can a micro-generation owner do with excess electricity they do not need?",
          "answerGuidance": [
            "Sell it back to the grid",
            "Feed it back into the National Grid",
            "Export it to the network"
          ],
          "hint": "Most systems are grid-connected for this reason.",
          "sourceTeachingPointIds": [
            "TP4"
          ]
        }
      ],
      "deeperQuestionText": "How does the role of a domestic consumer change when they install a grid-connected Photovoltaic (PV) system?",
      "deeperAnswerGuidance": [
        "They become a producer as well as a consumer",
        "They provide decentralized power to the grid",
        "They reduce their reliance on centralized power stations",
        "They contribute to the local energy supply"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP4"
      ],
      "hint": "Think about the direction of power flow and the consumer's new relationship with the grid."
    },
    {
      "title": "The Physics of High Voltage Transmission",
      "basicQuestions": [
        {
          "questionText": "What is the technical term for power lost as heat due to the resistance of a transmission cable?",
          "answerGuidance": [
            "I²R losses",
            "I2R losses"
          ],
          "hint": "It involves the symbol for current squared and resistance.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "When voltage is increased for transmission, what happens to the current level?",
          "answerGuidance": [
            "It decreases",
            "It goes down",
            "Lower current"
          ],
          "hint": "This change is necessary to maintain the same power while reducing heat.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        },
        {
          "questionText": "What is the primary benefit of reducing the current in long-distance transmission lines?",
          "answerGuidance": [
            "Reduce heat loss",
            "Minimize wasted energy",
            "Improve efficiency"
          ],
          "hint": "Think about what happens to the cables when current is high.",
          "sourceTeachingPointIds": [
            "TP4"
          ]
        }
      ],
      "deeperQuestionText": "Why is the use of high voltage essential for the economic viability of a national power grid?",
      "deeperAnswerGuidance": [
        "It minimizes energy wasted as heat",
        "It allows power to be moved over long distances efficiently",
        "Without it, I²R losses would be too high",
        "It ensures more generated power actually reaches the consumer"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP2",
        "TP4"
      ],
      "hint": "Consider the consequences of trying to move large amounts of power at low voltages over hundreds of miles."
    }
  ]
}

{
  "guidedPractice": {
    "title": "Guided Practice",
    "objective": "Identify a standard UK transmission voltage and explain the efficiency benefit of high-voltage transmission.",
    "retrievalTextLines": [
      "Recall the three standard UK transmission voltages: 400 kV, 275 kV, and 132 kV.",
      "Remember that power loss in a cable is calculated as I²R (heat loss).",
      "Increasing voltage allows the current (I) to be reduced for the same amount of power.",
      "Lower current results in significantly less energy wasted as heat during transmission."
    ],
    "questionText": "A large-scale wind farm is connected to the National Grid to supply a city 100 miles away. State one of the three standard UK transmission voltages used for this link and explain why the voltage is stepped up to such a high level for the journey.",
    "answerGuidance": [
      "The learner must state either 400 kV, 275 kV, or 132 kV.",
      "The explanation must state that high voltage reduces the current to minimize I²R heat losses (or energy waste) in the cables."
    ],
    "hint": "Think of the 'Big Three' voltages and how lowering the 'Amps' prevents the cables from getting hot and wasting power."
  },
  "practice": {
    "title": "Practice",
    "objective": "Differentiate between generation scales and identify the associated transmission voltage levels.",
    "retrievalTextLines": [
      "Large-scale generation (e.g., Nuclear, Gas, Coal) provides bulk power to the grid via the transmission network.",
      "Micro-generation (e.g., domestic Solar PV) is small-scale and usually located at the point of use.",
      "Transmission voltages are significantly higher than distribution or domestic voltages to ensure efficiency over long distances."
    ],
    "questionText": "Explain the main difference between a large-scale nuclear power station and a domestic solar PV system in terms of their generation category, and identify one of the specific high voltages used to transmit power from the nuclear station to the rest of the UK.",
    "answerGuidance": [
      "The learner must identify the nuclear station as large-scale (or centralized) generation and the solar PV as micro-generation (or local/small-scale).",
      "The learner must also state one of the transmission voltages: 400 kV, 275 kV, or 132 kV."
    ],
    "hint": "One is a massive central 'engine' for the country; the other is a small 'local' producer. Don't forget the specific 'kV' values for the long-distance lines."
  }
}

